+/**
+ * Notification log model — tracks sent notification history.
+ *
+ * Each log entry captures the full context of a notification delivery attempt:
+ * recipient, channel, type, timestamp, and delivery status.
+ */
+
+import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';
+
+/**
+ * Delivery status of a notification.
+ */
+export type DeliveryStatus = 'delivered' | 'failed' | 'skipped';
+
+/**
+ * A persistent record of a notification delivery attempt.
+ */
+export interface NotificationLog {
+  /** Unique log entry ID */
+  id: string;
+  /** The original notification ID */
+  notificationId: string;
+  /** Recipient identifier (email, user ID, webhook URL, etc.) */
+  recipient: string;
+  /** Delivery channel used */
+  channel: NotificationChannel;
+  /** Notification type */
+  type: NotificationType;
+  /** Priority level */
+  priority: NotificationPriority;
+  /** Subject line */
+  subject: string;
+  /** Delivery status */
+  status: DeliveryStatus;
+  /** Error message if delivery failed */
+  error?: string;
+  /** When the notification was sent */
+  sentAt: Date;
+  /** Optional user ID of the recipient */
+  userId?: string;
+  /** Optional metadata */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Query filters for searching notification history.
+ */
+export interface NotificationLogQuery {
+  /** Filter by recipient */
+  recipient?: string;
+  /** Filter by user ID */
+  userId?: string;
+  /** Filter by notification type */
+  type?: NotificationType;
+  /** Filter by delivery channel */
+  channel?: NotificationChannel;
+  /** Filter by delivery status */
+  status?: DeliveryStatus;
+  /** Filter by start date (inclusive) */
+  startDate?: Date;
+  /** Filter by end date (inclusive) */
+  endDate?: Date;
+}

