+/**
+ * Notification history service — logs and queries sent notification history.
+ *
+ * Integrates with NotificationService via setHistoryService() setter
+ * (same pattern as PreferencesService). Every sent notification is logged
+ * to the NotificationLogRepository for persistent tracking and querying.
+ */
+
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification delivery attempt.
+   * Called by NotificationService after each send() call.
+   */
+  log(payload: NotificationPayload, result: NotificationResult): NotificationLog {
+    const status: DeliveryStatus = result.success ? 'delivered' : 'failed';
+
+    const logEntry: NotificationLog = {
+      id: generateLogId(),
+      notificationId: payload.id,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      priority: payload.priority,
+      subject: payload.subject,
+      status,
+      sentAt: result.deliveredAt,
+    };
+
+    if (result.error) {
+      logEntry.error = result.error;
+    }
+    if (payload.metadata?.['userId']) {
+      logEntry.userId = payload.metadata['userId'] as string;
+    }
+    if (payload.metadata) {
+      logEntry.metadata = { ...payload.metadata };
+    }
+
+    this.repository.save(logEntry);
+    this.logger.info(`Logged notification ${payload.id} — ${status}`);
+    return logEntry;
+  }
+
+  /**
+   * Log a skipped notification (e.g., user opted out).
+   */
+  logSkipped(payload: NotificationPayload, reason: string): NotificationLog {
+    const logEntry: NotificationLog = {
+      id: generateLogId(),
+      notificationId: payload.id,
+      recipient: payload.recipient,
+      channel: payload.channel,
+      type: payload.type,
+      priority: payload.priority,
+      subject: payload.subject,
+      status: 'skipped',
+      error: reason,
+      sentAt: new Date(),
+    };
+
+    if (payload.metadata?.['userId']) {
+      logEntry.userId = payload.metadata['userId'] as string;
+    }
+    if (payload.metadata) {
+      logEntry.metadata = { ...payload.metadata };
+    }
+
+    this.repository.save(logEntry);
+    this.logger.info(`Logged skipped notification ${payload.id} — ${reason}`);
+    return logEntry;
+  }
+
+  /**
+   * Query notification history with flexible filters.
+   */
+  query(filters: NotificationLogQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filters.recipient && log.recipient !== filters.recipient) return false;
+      if (filters.userId && log.userId !== filters.userId) return false;
+      if (filters.type && log.type !== filters.type) return false;
+      if (filters.channel && log.channel !== filters.channel) return false;
+      if (filters.status && log.status !== filters.status) return false;
+      if (filters.startDate && log.sentAt < filters.startDate) return false;
+      if (filters.endDate && log.sentAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all logs for a specific user.
+   */
+  getByUser(userId: string): NotificationLog[] {
+    return this.repository.findByUserId(userId);
+  }
+
+  /**
+   * Get all logs of a specific notification type.
+   */
+  getByType(type: NotificationLog['type']): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all logs for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get a specific log entry by ID.
+   */
+  getById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

