/**
 * Notification log model — tracks sent notification history.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'delivered' | 'failed' | 'skipped';

/**
 * A persistent record of a notification delivery attempt.
 */
export interface NotificationLog {
  /** Unique log entry ID */
  id: string;
  /** The original notification ID */
  notificationId: string;
  /** Recipient identifier (email, user ID, webhook URL, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Notification type */
  type: NotificationType;
  /** Priority level */
  priority: NotificationPriority;
  /** Subject line */
  subject: string;
  /** Delivery status */
  status: DeliveryStatus;
  /** Error message if delivery failed */
  error?: string;
  /** When the notification was sent */
  sentAt: Date;
  /** Optional user ID of the recipient */
  userId?: string;
  /** Optional metadata */
  metadata?: Record<string, unknown>;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationLogQuery {
  /** Filter by recipient */
  recipient?: string;
  /** Filter by user ID */
  userId?: string;
  /** Filter by notification type */
  type?: NotificationType;
  /** Filter by delivery channel */
  channel?: NotificationChannel;
  /** Filter by delivery status */
  status?: DeliveryStatus;
  /** Filter by start date (inclusive) */
  startDate?: Date;
  /** Filter by end date (inclusive) */
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationLog['channel'],
      type: record['type'] as NotificationLog['type'],
      priority: record['priority'] as NotificationLog['priority'],
      subject: record['subject'] as string,
      status: record['status'] as NotificationLog['status'],
      sentAt: new Date(record['sentAt'] as string),
    };

    if (record['error']) {
      log.error = record['error'] as string;
    }
    if (record['userId']) {
      log.userId = record['userId'] as string;
    }
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }

    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      sentAt: entity.sentAt.toISOString(),
    };

    if (entity.error !== undefined) {
      record['error'] = entity.error;
    }
    if (entity.userId !== undefined) {
      record['userId'] = entity.userId;
    }
    if (entity.metadata !== undefined) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }

    return record;
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs for a specific user ID.
   */
  findByUserId(userId: string): NotificationLog[] {
    return this.findAll((log) => log.userId === userId);
  }

  /**
   * Find all logs of a specific notification type.
   */
  findByType(type: NotificationLog['type']): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * Integrates with NotificationService via setHistoryService() setter
 * (same pattern as PreferencesService). Every sent notification is logged
 * to the NotificationLogRepository for persistent tracking and querying.
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a notification delivery attempt.
   * Called by NotificationService after each send() call.
   */
  log(payload: NotificationPayload, result: NotificationResult): NotificationLog {
    const status: DeliveryStatus = result.success ? 'delivered' : 'failed';

    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: payload.id,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      subject: payload.subject,
      status,
      sentAt: result.deliveredAt,
    };

    if (result.error) {
      logEntry.error = result.error;
    }
    if (payload.metadata?.['userId']) {
      logEntry.userId = payload.metadata['userId'] as string;
    }
    if (payload.metadata) {
      logEntry.metadata = { ...payload.metadata };
    }

    this.repository.save(logEntry);
    this.logger.info(`Logged notification ${payload.id} — ${status}`);
    return logEntry;
  }

  /**
   * Log a skipped notification (e.g., user opted out).
   */
  logSkipped(payload: NotificationPayload, reason: string): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: payload.id,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      subject: payload.subject,
      status: 'skipped',
      error: reason,
      sentAt: new Date(),
    };

    if (payload.metadata?.['userId']) {
      logEntry.userId = payload.metadata['userId'] as string;
    }
    if (payload.metadata) {
      logEntry.metadata = { ...payload.metadata };
    }

    this.repository.save(logEntry);
    this.logger.info(`Logged skipped notification ${payload.id} — ${reason}`);
    return logEntry;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.userId && log.userId !== filters.userId) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.sentAt < filters.startDate) return false;
      if (filters.endDate && log.sentAt > filters.endDate) return false;
      return true;
    });
  }

  /**
   * Get all logs for a specific user.
   */
  getByUser(userId: string): NotificationLog[] {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get all logs of a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get a specific log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }
}

