import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent, UserUpdatedEvent } from '../../src/events/event-types.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let logRepo: NotificationLogRepository;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.setHistoryService(historyService);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('logging delivered notifications', () => {
    it('should log a successfully sent notification', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByUser('user-1');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.subject).toContain('Order Confirmation');
      expect(logs[0]?.userId).toBe('user-1');
    });

    it('should log multiple notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: { id: 'o1', userId: 'u1', items: [], total: 10, status: 'confirmed', createdAt: new Date(), updatedAt: new Date() },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: { id: 'o2', userId: 'u1', items: [], total: 20, status: 'shipped', createdAt: new Date(), updatedAt: new Date() },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(historyService.getCount()).toBe(2);
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'user:updated',
        user: { id: 'u1', name: 'Alice B', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        changes: ['name'],
        timestamp: new Date(),
      } as UserUpdatedEvent);

      const log1 = historyService.getById('nlog-0001');
      const log2 = historyService.getById('nlog-0002');
      expect(log1).toBeDefined();
      expect(log2).toBeDefined();
      expect(log1?.type).toBe('welcome');
      expect(log2?.type).toBe('account_updated');
    });
  });

  describe('logging failed notifications', () => {
    it('should log a failed notification when no adapter is registered', async () => {
      const noAdapterEventBus = new EventBus();
      const noAdapterService = new NotificationService(noAdapterEventBus);
      noAdapterService.setHistoryService(historyService);

      const result = await noAdapterService.send({
        id: 'test-fail',
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        createdAt: new Date(),
      });

      expect(result.success).toBe(false);
      const logs = historyService.getByRecipient('test@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toContain('No adapter registered');
    });
  });

  describe('logging skipped notifications', () => {
    it('should log a skipped notification when user opts out', async () => {
      const prefsRepo = new PreferencesRepository(db);
      const prefsService = new PreferencesService(prefsRepo);
      notificationService.setPreferencesService(prefsService);

      // Opt user out of order_confirmation
      prefsService.updateEmailPreferences('user-1', {
        subscribedTypes: ['order_status_update', 'welcome', 'account_updated'],
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getByUser('user-1');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('skipped');
      expect(logs[0]?.error).toContain('opted out');
    });
  });

  describe('query by user', () => {
    it('should return logs for a specific user', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'alice@test.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u2', name: 'Bob', email: 'bob@test.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      expect(historyService.getByUser('u1')).toHaveLength(1);
      expect(historyService.getByUser('u2')).toHaveLength(1);
      expect(historyService.getByUser('u3')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: { id: 'o1', userId: 'u1', items: [], total: 10, status: 'confirmed', createdAt: new Date(), updatedAt: new Date() },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(historyService.getByType('welcome')).toHaveLength(1);
      expect(historyService.getByType('order_status_update')).toHaveLength(1);
      expect(historyService.getByType('order_confirmation')).toHaveLength(0);
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'alice@test.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      expect(historyService.getByRecipient('alice@test.com')).toHaveLength(1);
      expect(historyService.getByRecipient('nobody@test.com')).toHaveLength(0);
    });
  });

  describe('query with filters', () => {
    it('should filter by date range', async () => {
      const early = new Date('2026-01-01T00:00:00Z');
      const mid = new Date('2026-06-15T00:00:00Z');
      const late = new Date('2026-12-31T00:00:00Z');

      // Directly log entries with specific timestamps
      const basePayload: NotificationPayload = {
        id: 'n1',
        type: 'welcome',
        channel: 'email',
        recipient: 'a@b.com',
        subject: 'Welcome',
        body: 'Hello',
        priority: 'normal',
        createdAt: early,
        metadata: { userId: 'u1' },
      };

      historyService.log(basePayload, { success: true, notificationId: 'n1', channel: 'email', deliveredAt: early });
      historyService.log(
        { ...basePayload, id: 'n2', createdAt: late },
        { success: true, notificationId: 'n2', channel: 'email', deliveredAt: late },
      );

      const results = historyService.query({ startDate: mid, endDate: new Date('2027-01-01T00:00:00Z') });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('n2');
    });

    it('should combine multiple filters', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'alice@test.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: { id: 'o1', userId: 'u1', items: [], total: 10, status: 'confirmed', createdAt: new Date(), updatedAt: new Date() },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      const results = historyService.query({ userId: 'u1', type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should filter by status', async () => {
      const noAdapterEventBus = new EventBus();
      const noAdapterService = new NotificationService(noAdapterEventBus);
      noAdapterService.setHistoryService(historyService);

      // Successful via main service
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      // Failed via no-adapter service
      await noAdapterService.send({
        id: 'fail-1',
        type: 'welcome',
        channel: 'email',
        recipient: 'b@b.com',
        subject: 'Test',
        body: 'Body',
        priority: 'normal',
        createdAt: new Date(),
      });

      expect(historyService.query({ status: 'delivered' })).toHaveLength(1);
      expect(historyService.query({ status: 'failed' })).toHaveLength(1);
    });

    it('should filter by channel', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      expect(historyService.query({ channel: 'email' })).toHaveLength(1);
      expect(historyService.query({ channel: 'webhook' })).toHaveLength(0);
    });
  });

  describe('backwards compatibility', () => {
    it('should work without history service configured', async () => {
      const plainEventBus = new EventBus();
      const plainService = new NotificationService(plainEventBus);
      const plainAdapter = new EmailAdapter();
      plainService.registerAdapter(plainAdapter);
      // No setHistoryService call

      await plainEventBus.emit({
        type: 'user:created',
        user: { id: 'u1', name: 'Alice', email: 'a@b.com', role: 'member', createdAt: new Date(), updatedAt: new Date() },
        timestamp: new Date(),
      } as UserCreatedEvent);

      // Should send normally without errors
      expect(plainService.getNotificationCount()).toBe(1);
      expect(plainAdapter.getSentEmails()).toHaveLength(1);
    });
  });
});
